CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_131" 
AFTER INSERT ON ORION_131
FOR EACH ROW
DECLARE
    v_usuario NUMBER(5,0);
    v_deposito_destino NUMBER(3,0);
    v_nr_sugestao NUMBER(9,0);
BEGIN
    -- Obter dados da ORION_130 filtrando pelo NUMERO_CAIXA da ORION_131
    SELECT USUARIO, DEPOSITO_DESTINO, NR_SUGESTAO
    INTO v_usuario, v_deposito_destino, v_nr_sugestao
    FROM ORION_130
    WHERE NUMERO_CAIXA = :NEW.NUMERO_CAIXA;

    -- Inserir os dados na tabela ORION_133
    INSERT INTO ORION_133 (
        NUMERO_TAG,
        NUMERO_CAIXA,
        PERIODO_PRODUCAO,
        ORDEM_PRODUCAO,
        ORDEM_CONFECCAO,
        SEQUENCIA,
        PEDIDO,
        SEQ_PEDIDO,
        NIVEL,
        GRUPO,
        SUBGRUPO,
        ITEM,
        VOLUME_PEDIDO,
        USUARIO,
        DEPOSITO_DESTINO,
        NR_SUGESTAO,
        DATA_HORA_LEITURA
    ) VALUES (
        :NEW.NUMERO_TAG,
        :NEW.NUMERO_CAIXA,
        :NEW.PERIODO_PRODUCAO,
        :NEW.ORDEM_PRODUCAO,
        :NEW.ORDEM_CONFECCAO,
        :NEW.SEQUENCIA,
        :NEW.PEDIDO,
        :NEW.SEQ_PEDIDO,
        :NEW.NIVEL,
        :NEW.GRUPO,
        :NEW.SUBGRUPO,
        :NEW.ITEM,
        :NEW.VOLUME_PEDIDO,
        v_usuario,
        v_deposito_destino,
        v_nr_sugestao,
        SYSDATE
    );
END;
/
ALTER TRIGGER "ORION"."TR_ORION_131" ENABLE;

