CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."LIVE_TR_ORION_CFC_220_DATA_ENTREGA_GERFAC" 
AFTER INSERT OR UPDATE ON ORION_CFC_220
FOR EACH ROW
DECLARE
  v_numero_ordem NUMBER(9);
  v_existe NUMBER;
BEGIN

  IF :NEW.estagio = 20 AND :NEW.ordem_confeccao = 0 AND :NEW.tipo_observacao = 12 AND :NEW.observacao_adicional IS NOT NULL THEN

    SELECT COUNT(*)
    INTO v_existe
    FROM orion_cfc_221
    WHERE id = :NEW.tipo_observacao
      AND formato = 'DATA';

    IF v_existe > 0 THEN

      BEGIN
        -- Obter ordem de produção de PCPC_040
        SELECT DISTINCT(pc40.numero_ordem)
        INTO v_numero_ordem
        FROM pcpc_040 pc40, obrf_080 ob80
        WHERE pc40.numero_ordem = ob80.numero_ordem
          AND pc40.ordem_producao = :NEW.ordem_producao
          AND (:NEW.tamanho_ordem_confeccao IS NULL OR pc40.PROCONF_SUBGRUPO = :NEW.tamanho_ordem_confeccao)
          AND ob80.codigo_servico IN (7, 20, 21);
      EXCEPTION
        WHEN OTHERS THEN
          v_numero_ordem := 0;
      END;

      IF (v_numero_ordem != 0) THEN
        -- Atualizar a data de entrega na OBRF_080
        UPDATE obrf_080
        SET data_entrega = TO_DATE(:NEW.observacao_adicional, 'DD/MM/YYYY')
        WHERE numero_ordem = v_numero_ordem
        AND codigo_servico IN (7,20,21);
      END IF;
    END IF;
  END IF;
END LIVE_TR_ORION_CFC_220_DATA_ENTREGA_GERFAC;

/
ALTER TRIGGER "ORION"."LIVE_TR_ORION_CFC_220_DATA_ENTREGA_GERFAC" ENABLE;

