CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_CFC_280" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_CFC_280
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.CLI_PED_CGC_CLI9 IS NOT NULL) OR
       (:OLD.CLI_PED_CGC_CLI9 <> :NEW.CLI_PED_CGC_CLI9 OR :OLD.CLI_PED_CGC_CLI4 <> :NEW.CLI_PED_CGC_CLI4))
    THEN
        :NEW.CLI_PED_CGC_CLI_R := CASE
            WHEN NVL(:NEW.CLI_PED_CGC_CLI4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.CLI_PED_CGC_CLI9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.CLI_PED_CGC_CLI9), 8, '0')
        END;
        :NEW.CLI_PED_CGC_CLI_O := LPAD(TO_CHAR(:NEW.CLI_PED_CGC_CLI4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.CLI_PED_CGC_CLI9 := :NEW.CLI_PED_CGC_CLI_R;
        :NEW.CLI_PED_CGC_CLI4 := :NEW.CLI_PED_CGC_CLI_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.CLI_PED_CGC_CLI_R := LTRIM(TO_CHAR(:NEW.CLI_PED_CGC_CLI_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.CLI_PED_CGC_CLI_R := CASE
        WHEN (NVL(:NEW.CLI_PED_CGC_CLI_O, '0') = '0'
           OR NVL(:NEW.CLI_PED_CGC_CLI_O, '0') = '00'
           OR NVL(:NEW.CLI_PED_CGC_CLI_O, '0') = '000'
           OR NVL(:NEW.CLI_PED_CGC_CLI_O, '0') = '0000')
        THEN LPAD(:NEW.CLI_PED_CGC_CLI_R, 9, '0')
        ELSE LPAD(:NEW.CLI_PED_CGC_CLI_R, 8, '0')
    END;
    :NEW.CLI_PED_CGC_CLI_O := LPAD(:NEW.CLI_PED_CGC_CLI_O, 4, '0');

END;
/
ALTER TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_CFC_280" ENABLE;

