CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_CFC_388" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_CFC_388
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.FORNECEDOR9 IS NOT NULL) OR
       (:OLD.FORNECEDOR9 <> :NEW.FORNECEDOR9 OR :OLD.FORNECEDOR4 <> :NEW.FORNECEDOR4))
    THEN
        :NEW.FORNECEDOR_R := CASE
            WHEN NVL(:NEW.FORNECEDOR4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.FORNECEDOR9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.FORNECEDOR9), 8, '0')
        END;
        :NEW.FORNECEDOR_O := LPAD(TO_CHAR(:NEW.FORNECEDOR4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.FORNECEDOR9 := :NEW.FORNECEDOR_R;
        :NEW.FORNECEDOR4 := :NEW.FORNECEDOR_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.FORNECEDOR_R := LTRIM(TO_CHAR(:NEW.FORNECEDOR_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.FORNECEDOR_R := CASE
        WHEN (NVL(:NEW.FORNECEDOR_O, '0') = '0'
           OR NVL(:NEW.FORNECEDOR_O, '0') = '00'
           OR NVL(:NEW.FORNECEDOR_O, '0') = '000'
           OR NVL(:NEW.FORNECEDOR_O, '0') = '0000')
        THEN LPAD(:NEW.FORNECEDOR_R, 9, '0')
        ELSE LPAD(:NEW.FORNECEDOR_R, 8, '0')
    END;
    :NEW.FORNECEDOR_O := LPAD(:NEW.FORNECEDOR_O, 4, '0');

END;
/
ALTER TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_CFC_388" ENABLE;

