CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."LIVE_TR_ORION_COM_250_1" 
   after insert or update on "ORION_COM_250"
for each row

-- JOÃO L. - CH: 34919

begin
        if (:new.data_desbloqueio is not null)
        then
           begin
             update cpag_010 p
             set sit_bloqueio = 0 --- LIBERADO
                 where p.cgc_9 = :new.cnpj_fornecedor_9
                   and p.cgc_4 = :new.cnpj_fornecedor_4
                   and p.cgc_2 = :new.cnpj_fornecedor_2
                   and not exists ( select 1 from (
                                       select j.nr_duplicata titulo, sum(j.valor_parcela) valorTitulo, sum(l.valor_pago) valorPago from cpag_010 j, cpag_015 l
                                              where j.nr_duplicata = p.nr_duplicata
                                                    and j.tipo_titulo = p.tipo_titulo
                                                    and j.cgc_9 = p.cgc_9
                                                    and j.cgc_4 = p.cgc_4
                                                    and j.cgc_2 = p.cgc_2
                                                    and j.nr_duplicata = l.dupl_for_nrduppag
                                                    and j.parcela = l.dupl_for_no_parc
                                                    and j.cgc_9 = l.dupl_for_for_cli9
                                                    and j.cgc_4 = l.dupl_for_for_cli4
                                                    and j.cgc_2 = l.dupl_for_for_cli2
                                                    and j.tipo_titulo = l.dupl_for_tipo_tit
                                                    and l.data_pagamento is not null
                                                    group by j.nr_duplicata ) titulo
                                where (titulo.valorTitulo - titulo.valorPago = 0));
           end;
        end if;

        if (:new.data_desbloqueio is null)
        then
           begin
             update cpag_010 p
             set sit_bloqueio = 1 --- BLOQUEADO
                 where p.cgc_9 = :new.cnpj_fornecedor_9
                   and p.cgc_4 = :new.cnpj_fornecedor_4
                   and p.cgc_2 = :new.cnpj_fornecedor_2
                    and not exists ( select 1 from (
                                       select j.nr_duplicata titulo, sum(j.valor_parcela) valorTitulo, sum(l.valor_pago) valorPago from cpag_010 j, cpag_015 l
                                              where j.nr_duplicata = p.nr_duplicata
                                                    and j.tipo_titulo = p.tipo_titulo
                                                    and j.cgc_9 = p.cgc_9
                                                    and j.cgc_4 = p.cgc_4
                                                    and j.cgc_2 = p.cgc_2
                                                    and j.nr_duplicata = l.dupl_for_nrduppag
                                                    and j.parcela = l.dupl_for_no_parc
                                                    and j.cgc_9 = l.dupl_for_for_cli9
                                                    and j.cgc_4 = l.dupl_for_for_cli4
                                                    and j.cgc_2 = l.dupl_for_for_cli2
                                                    and j.tipo_titulo = l.dupl_for_tipo_tit
                                                    and l.data_pagamento is not null
                                                    group by j.nr_duplicata ) titulo
                                where (titulo.valorTitulo - titulo.valorPago = 0));
           end;
        end if;
end LIVE_TR_ORION_COM_250_1;

/
ALTER TRIGGER "ORION"."LIVE_TR_ORION_COM_250_1" ENABLE;
  CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_COM_250" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_COM_250
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.CNPJ_FORNECEDOR_9 IS NOT NULL) OR
       (:OLD.CNPJ_FORNECEDOR_9 <> :NEW.CNPJ_FORNECEDOR_9 OR :OLD.CNPJ_FORNECEDOR_4 <> :NEW.CNPJ_FORNECEDOR_4))
    THEN
        :NEW.CNPJ_FORNECEDOR_R := CASE
            WHEN NVL(:NEW.CNPJ_FORNECEDOR_4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.CNPJ_FORNECEDOR_9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.CNPJ_FORNECEDOR_9), 8, '0')
        END;
        :NEW.CNPJ_FORNECEDOR_O := LPAD(TO_CHAR(:NEW.CNPJ_FORNECEDOR_4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.CNPJ_FORNECEDOR_9 := :NEW.CNPJ_FORNECEDOR_R;
        :NEW.CNPJ_FORNECEDOR_4 := :NEW.CNPJ_FORNECEDOR_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.CNPJ_FORNECEDOR_R := LTRIM(TO_CHAR(:NEW.CNPJ_FORNECEDOR_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.CNPJ_FORNECEDOR_R := CASE
        WHEN (NVL(:NEW.CNPJ_FORNECEDOR_O, '0') = '0'
           OR NVL(:NEW.CNPJ_FORNECEDOR_O, '0') = '00'
           OR NVL(:NEW.CNPJ_FORNECEDOR_O, '0') = '000'
           OR NVL(:NEW.CNPJ_FORNECEDOR_O, '0') = '0000')
        THEN LPAD(:NEW.CNPJ_FORNECEDOR_R, 9, '0')
        ELSE LPAD(:NEW.CNPJ_FORNECEDOR_R, 8, '0')
    END;
    :NEW.CNPJ_FORNECEDOR_O := LPAD(:NEW.CNPJ_FORNECEDOR_O, 4, '0');

END;
/
