CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_COM_400_LOG" 
AFTER INSERT OR UPDATE ON ORION_COM_400
FOR EACH ROW
DECLARE
  v_descricao VARCHAR2(4000);
BEGIN
  IF INSERTING THEN
      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:OLD.id_loja, :NEW.cod_usuario, SYSDATE, 'I', 'ORION_COM_400', :NEW.descricao);

  ELSIF UPDATING THEN

      v_descricao := 'Alterado o(s) campo(s): ';

      IF :OLD.descricao <> :NEW.descricao THEN
          v_descricao := v_descricao || 'descricao, ';
      END IF;

      IF :OLD.apelido <> :NEW.apelido THEN
          v_descricao := v_descricao || 'apelido, ';
      END IF;

      IF :OLD.razao_social <> :NEW.razao_social THEN
          v_descricao := v_descricao || 'Razão Social, ';
      END IF;

      IF :OLD.cnpj9 <> :NEW.cnpj9 THEN
          v_descricao := v_descricao || 'Cnpj9, ';
      END IF;

      IF :OLD.cnpj4 <> :NEW.cnpj4 THEN
          v_descricao := v_descricao || 'Cnpj4, ';
      END IF;

      IF :OLD.cnpj2 <> :NEW.cnpj2 THEN
          v_descricao := v_descricao || 'Cnpj2, ';
      END IF;

      IF :OLD.inscricao_estadual <> :NEW.inscricao_estadual THEN
      v_descricao := v_descricao || 'Inscrição Estadual, ';
      END IF;

      IF :OLD.cod_funcionario <> :NEW.cod_funcionario THEN
          v_descricao := v_descricao || 'Código do Funcionário, ';
      END IF;

      IF :OLD.cep <> :NEW.cep THEN
          v_descricao := v_descricao || 'CEP, ';
      END IF;

      IF :OLD.endereco <> :NEW.endereco THEN
          v_descricao := v_descricao || 'Endereço, ';
      END IF;

      IF :OLD.telefone1 <> :NEW.telefone1 THEN
          v_descricao := v_descricao || 'Telefone1, ';
      END IF;

      IF :OLD.telefone2 <> :NEW.telefone2 THEN
          v_descricao := v_descricao || 'Telefone2, ';
      END IF;

      IF :OLD.portal <> :NEW.portal THEN
          v_descricao := v_descricao || 'Portal, ';
      END IF;

      IF :OLD.id_portal <> :NEW.id_portal THEN
          v_descricao := v_descricao || 'ID Portal, ';
      END IF;

      IF :OLD.data_inauguracao <> :NEW.data_inauguracao THEN
          v_descricao := v_descricao || 'Data de Inauguração, ';
      END IF;

      IF :OLD.metragem <> :NEW.metragem THEN
          v_descricao := v_descricao || 'Metragem, ';
      END IF;

      IF :OLD.id_regiao <> :NEW.id_regiao THEN
          v_descricao := v_descricao || 'Região, ';
      END IF;

      IF :OLD.abre_aos_domingos <> :NEW.abre_aos_domingos THEN
          v_descricao := v_descricao || 'Abre aos Domingos, ';
      END IF;

      IF :OLD.omny_channel <> :NEW.omny_channel THEN
          v_descricao := v_descricao || 'Omny Channel, ';
      END IF;

      IF :OLD.id_rede <> :NEW.id_rede THEN
          v_descricao := v_descricao || 'Rede, ';
      END IF;

      IF :OLD.porc_franchising <> :NEW.porc_franchising THEN
          v_descricao := v_descricao || 'Porcentagem de Franchising, ';
      END IF;

      IF :OLD.ponto_retirada <> :NEW.ponto_retirada THEN
          v_descricao := v_descricao || 'Ponto de Retirada, ';
      END IF;

      IF :OLD.cupom_desconto_loja <> :NEW.cupom_desconto_loja THEN
          v_descricao := v_descricao || 'Cupom de Desconto da Loja, ';
      END IF;

      IF :OLD.situacao <> :NEW.situacao THEN
          v_descricao := v_descricao || 'Situação, ';
      END IF;

      IF :OLD.nr_dias_receb_mercadoria <> :NEW.nr_dias_receb_mercadoria THEN
          v_descricao := v_descricao || 'N° Dias Recebimento Mercadoria, ';
      END IF;

      v_descricao := RTRIM(v_descricao, ', ');

      IF v_descricao <> 'Alterado o(s) campo(s):' THEN 
            INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
            VALUES (:NEW.id_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'U', 'ORION_COM_400', v_descricao);
      END IF;
  END IF;
END;

/
ALTER TRIGGER "ORION"."TR_ORION_COM_400_LOG" ENABLE;
  CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_COM_400" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_COM_400
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.CNPJ9 IS NOT NULL) OR
       (:OLD.CNPJ9 <> :NEW.CNPJ9 OR :OLD.CNPJ4 <> :NEW.CNPJ4))
    THEN
        :NEW.CNPJ_R := CASE
            WHEN NVL(:NEW.CNPJ4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.CNPJ9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.CNPJ9), 8, '0')
        END;
        :NEW.CNPJ_O := LPAD(TO_CHAR(:NEW.CNPJ4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.CNPJ9 := :NEW.CNPJ_R;
        :NEW.CNPJ4 := :NEW.CNPJ_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.CNPJ_R := LTRIM(TO_CHAR(:NEW.CNPJ_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.CNPJ_R := CASE
        WHEN (NVL(:NEW.CNPJ_O, '0') = '0'
           OR NVL(:NEW.CNPJ_O, '0') = '00'
           OR NVL(:NEW.CNPJ_O, '0') = '000'
           OR NVL(:NEW.CNPJ_O, '0') = '0000')
        THEN LPAD(:NEW.CNPJ_R, 9, '0')
        ELSE LPAD(:NEW.CNPJ_R, 8, '0')
    END;
    :NEW.CNPJ_O := LPAD(:NEW.CNPJ_O, 4, '0');

END;
/
