CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_COM_415_LOG" 
AFTER INSERT OR UPDATE ON ORION_COM_415
FOR EACH ROW
DECLARE
  v_descricao VARCHAR2(4000);
BEGIN
  IF INSERTING THEN
    IF :NEW.qtde <> 0 AND :NEW.valor <> 0 THEN
      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'I', 'ORION_COM_415',
               'Nova Meta Mensal: ' || :NEW.mes || '/' || :NEW.ano || '. Na Qtde: ' || :NEW.qtde || ' e No Valor de: ' || :NEW.valor);
    END IF;
  ELSIF UPDATING THEN
      v_descricao := 'Alterado o(s) campo(s): ';

      IF (:OLD.valor <> :NEW.valor) AND (:OLD.qtde <> :NEW.qtde)THEN
          v_descricao := v_descricao || 'Qtde dê: ' || :OLD.qtde || ' para: ' || :NEW.qtde || ', ' || 'e Valor dê: ' || :OLD.valor || ' para: ' || :NEW.valor || ' de: ' || :NEW.mes || '/' || :NEW.ano;
      ELSIF (:OLD.valor = :NEW.valor) AND (:OLD.qtde <> :NEW.qtde) THEN
          v_descricao := v_descricao || 'Qtde dê: ' || :OLD.qtde || ' para: ' || :NEW.qtde || ' de: ' || :NEW.mes || '/' || :NEW.ano;
      ELSIF (:OLD.valor <> :NEW.valor) AND (:OLD.qtde = :NEW.qtde) THEN
          v_descricao := v_descricao || 'Valor dê: ' || :OLD.valor || ' para: ' || :NEW.valor || ' de: ' || :NEW.mes || '/' || :NEW.ano;
      END IF;

      IF v_descricao <> 'Alterado o(s) campo(s): ' THEN
      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'U', 'ORION_COM_415', v_descricao);
      END IF;
  END IF;
END;

/
