CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_COM_435_LOG" 
AFTER INSERT OR UPDATE ON ORION_COM_435
FOR EACH ROW
DECLARE
  v_descricao VARCHAR2(4000);
  v_cargo VARCHAR2(20);
BEGIN
  IF INSERTING THEN
    IF ((:NEW.percentual_inicio > 0)  OR (:NEW.percentual_fim > 0) OR (:NEW.comissao > 0)) THEN
      IF (:NEW.cargo = 1) THEN
        v_cargo := 'Vendedor';
      ELSE
        v_cargo := 'Gerente';
      END IF;
      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'I', 'ORION_COM_435', 'Nova Faixa de Comissão para Loja: ' || :NEW.cod_loja || ' do: ' || v_cargo);
    END IF;

  ELSIF UPDATING THEN
      IF (:NEW.cargo = 1) THEN
         v_cargo := 'Vendedor';
      ELSE
         v_cargo := 'Gerente';
      END IF;
      
      IF (:OLD.percentual_inicio <> :NEW.percentual_inicio) THEN
          v_descricao := 'Valor do Percentual Inicio foi alterado de: ' || :OLD.percentual_inicio || '% para: ' || :NEW.percentual_inicio || '% do: ' || v_cargo || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF (:OLD.percentual_fim <> :NEW.percentual_fim) THEN
          v_descricao := 'Valor do Percentual Final foi alterado de: ' || :OLD.percentual_fim || '% para: ' || :NEW.percentual_fim || '% do: ' || v_cargo || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF (:OLD.comissao <> :NEW.comissao) THEN
          v_descricao := 'Valor da Comissao foi alterado de: ' || :OLD.comissao || '% para: ' || :NEW.comissao || '% do: ' || v_cargo || ' da loja: ' || :NEW.cod_loja;
      END IF;

      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'U', 'ORION_COM_435', v_descricao);

  END IF;
END;

/
