CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_COM_445_LOG" 
AFTER INSERT OR UPDATE ON ORION_COM_445
FOR EACH ROW
DECLARE
  v_descricao VARCHAR2(4000);
BEGIN
  IF INSERTING THEN
    IF ((:NEW.valor_inicio > 0)  OR (:NEW.valor_fim > 0) OR (:NEW.comissao > 0)) THEN

      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'I', 'ORION_COM_445', 'Nova Faixa de Comissão Online para Loja: ' || :NEW.cod_loja);
    END IF;

  ELSIF UPDATING THEN

      IF (:OLD.valor_inicio <> :NEW.valor_inicio) THEN
          v_descricao := 'Valor Inicial foi alterado de: ' || :OLD.valor_inicio || ' para: ' || :NEW.valor_inicio || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF (:OLD.valor_fim <> :NEW.valor_fim) THEN
          v_descricao := 'Valor Final foi alterado de: ' || :OLD.valor_fim || ' para: ' || :NEW.valor_fim  || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF (:OLD.comissao <> :NEW.comissao) THEN
          v_descricao := 'Valor da Comissao foi alterado de: ' || :OLD.comissao || ' para: ' || :NEW.comissao || ' da loja: ' || :NEW.cod_loja;
      END IF;

      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'U', 'ORION_COM_445', v_descricao);

  END IF;
END;

/
