CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_COM_446_LOG" 
AFTER INSERT OR UPDATE ON ORION_COM_446
FOR EACH ROW
DECLARE
  v_descricao VARCHAR2(4000);
  v_tipo_loja VARCHAR2(30);
BEGIN
  IF INSERTING THEN
    IF (:NEW.nome_vendedor <> '' AND :NEW.bonus_com_meta > 0 AND :NEW.bonus_sem_meta > 0) THEN
      IF :NEW.tipo_loja = 1 THEN
        v_tipo_loja := 'LJ Pequena';
      ELSE
        v_tipo_loja := 'LJ Grande';
      END IF;

      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'I', 'ORION_COM_446', 'Novo Lançamento Bônus para ' || v_tipo_loja  || ' para Loja: ' || :NEW.cod_loja);
    END IF;

  ELSIF UPDATING THEN

      IF :NEW.tipo_loja = 1 THEN
        v_tipo_loja := 'LJ Pequena';
      ELSE
        v_tipo_loja := 'LJ Grande';
      END IF;

      IF (:OLD.nome_vendedor <> :NEW.nome_vendedor) THEN
          v_descricao := 'Nome Vendedor alterado de: ' || :OLD.nome_vendedor || ' para: ' || :NEW.nome_vendedor || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF (:OLD.bonus_com_meta <> :NEW.bonus_com_meta) THEN
          v_descricao := 'Bônus com Meta alterada de: ' || :OLD.bonus_com_meta || ' para: ' || :NEW.bonus_com_meta || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF (:OLD.bonus_sem_meta <> :NEW.bonus_sem_meta) THEN
          v_descricao := 'Bônus sem Meta alterada de: ' || :OLD.bonus_sem_meta || ' para: ' || :NEW.bonus_sem_meta || ' da loja: ' || :NEW.cod_loja;
      END IF;


      INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
      VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'U', 'ORION_COM_446', v_descricao);

  END IF;
END;

/
