      END IF;

      IF (:OLD.valor <> :NEW.valor) THEN
          v_descricao := 'Valor alterado de: ' || :OLD.valor || ' para: ' || :NEW.valor || ' da loja: ' || :NEW.cod_loja;
      END IF;

      IF v_descricao <> '' THEN
        INSERT INTO ORION_LOG (chave_registro, cod_usuario, data_hora, tipo, tabela, descricao)
        VALUES (:NEW.cod_loja, :NEW.usuario_ult_alteracao, SYSDATE, 'U', 'ORION_COM_447', v_descricao);
      END IF;

  END IF;
END;

