CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_COM_610" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_COM_610
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.CNPJ_9 IS NOT NULL) OR
       (:OLD.CNPJ_9 <> :NEW.CNPJ_9 OR :OLD.CNPJ_4 <> :NEW.CNPJ_4))
    THEN
        :NEW.CNPJ_R := CASE
            WHEN NVL(:NEW.CNPJ_4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.CNPJ_9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.CNPJ_9), 8, '0')
        END;
        :NEW.CNPJ_O := LPAD(TO_CHAR(:NEW.CNPJ_4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.CNPJ_9 := :NEW.CNPJ_R;
        :NEW.CNPJ_4 := :NEW.CNPJ_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.CNPJ_R := LTRIM(TO_CHAR(:NEW.CNPJ_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.CNPJ_R := CASE
        WHEN (NVL(:NEW.CNPJ_O, '0') = '0'
           OR NVL(:NEW.CNPJ_O, '0') = '00'
           OR NVL(:NEW.CNPJ_O, '0') = '000'
           OR NVL(:NEW.CNPJ_O, '0') = '0000')
        THEN LPAD(:NEW.CNPJ_R, 9, '0')
        ELSE LPAD(:NEW.CNPJ_R, 8, '0')
    END;
    :NEW.CNPJ_O := LPAD(:NEW.CNPJ_O, 4, '0');

END;
/
ALTER TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_COM_610" ENABLE;

