CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TR_ORION_ENG_260_BLOQUEIO_OPERACAO" 
BEFORE UPDATE OR DELETE OR INSERT ON orion_eng_260
FOR EACH ROW
BEGIN
  IF (UPDATING OR DELETING) THEN
    IF :OLD.cod_operacao BETWEEN 20000 AND 53500 THEN
      RAISE_APPLICATION_ERROR(-20001, 'Operação ' || :OLD.cod_operacao || ' não pode ser alterada ou excluída.');
    END IF;
  END IF;
  
  IF (INSERTING) THEN
    IF :NEW.cod_operacao BETWEEN 20000 AND 53500 THEN
      RAISE_APPLICATION_ERROR(-20002, 'Operação ' || :NEW.cod_operacao || ' não pode ser alterada.');
    END IF;
  END IF;
END;
/
ALTER TRIGGER "ORION"."TR_ORION_ENG_260_BLOQUEIO_OPERACAO" DISABLE;

