CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_FIN_130" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_FIN_130
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.CGC9 IS NOT NULL) OR
       (:OLD.CGC9 <> :NEW.CGC9 OR :OLD.CGC4 <> :NEW.CGC4))
    THEN
        :NEW.CGC_R := CASE
            WHEN NVL(:NEW.CGC4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.CGC9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.CGC9), 8, '0')
        END;
        :NEW.CGC_O := LPAD(TO_CHAR(:NEW.CGC4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.CGC9 := :NEW.CGC_R;
        :NEW.CGC4 := :NEW.CGC_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.CGC_R := LTRIM(TO_CHAR(:NEW.CGC_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.CGC_R := CASE
        WHEN (NVL(:NEW.CGC_O, '0') = '0'
           OR NVL(:NEW.CGC_O, '0') = '00'
           OR NVL(:NEW.CGC_O, '0') = '000'
           OR NVL(:NEW.CGC_O, '0') = '0000')
        THEN LPAD(:NEW.CGC_R, 9, '0')
        ELSE LPAD(:NEW.CGC_R, 8, '0')
    END;
    :NEW.CGC_O := LPAD(:NEW.CGC_O, 4, '0');

END;
/
ALTER TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_FIN_130" ENABLE;

