CREATE OR REPLACE EDITIONABLE TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_SUP_010" 
    BEFORE INSERT OR UPDATE ON ORION.ORION_SUP_010
    FOR EACH ROW
BEGIN

    IF ((INSERTING AND :NEW.TRANSP_CNPJ9 IS NOT NULL) OR
       (:OLD.TRANSP_CNPJ9 <> :NEW.TRANSP_CNPJ9 OR :OLD.TRANSP_CNPJ4 <> :NEW.TRANSP_CNPJ4))
    THEN
        :NEW.TRANSP_CNPJ_R := CASE
            WHEN NVL(:NEW.TRANSP_CNPJ4, 0) = 0
            THEN LPAD(TO_CHAR(:NEW.TRANSP_CNPJ9), 9, '0')
            ELSE LPAD(TO_CHAR(:NEW.TRANSP_CNPJ9), 8, '0')
        END;
        :NEW.TRANSP_CNPJ_O := LPAD(TO_CHAR(:NEW.TRANSP_CNPJ4), 4, '0');
    ELSIF ORION.PKG_CNPJ_MIGRACAO.FN_SYNC_REVERSA_ATIVA THEN
        :NEW.TRANSP_CNPJ9 := :NEW.TRANSP_CNPJ_R;
        :NEW.TRANSP_CNPJ4 := :NEW.TRANSP_CNPJ_O;
    END IF;

    -- Sempre remover 0 a esquerda
    :NEW.TRANSP_CNPJ_R := LTRIM(TO_CHAR(:NEW.TRANSP_CNPJ_R), '0');

    -- Pos-processamento: normalizar LPAD das colunas VARCHAR2
    :NEW.TRANSP_CNPJ_R := CASE
        WHEN (NVL(:NEW.TRANSP_CNPJ_O, '0') = '0'
           OR NVL(:NEW.TRANSP_CNPJ_O, '0') = '00'
           OR NVL(:NEW.TRANSP_CNPJ_O, '0') = '000'
           OR NVL(:NEW.TRANSP_CNPJ_O, '0') = '0000')
        THEN LPAD(:NEW.TRANSP_CNPJ_R, 9, '0')
        ELSE LPAD(:NEW.TRANSP_CNPJ_R, 8, '0')
    END;
    :NEW.TRANSP_CNPJ_O := LPAD(:NEW.TRANSP_CNPJ_O, 4, '0');

END;
/
ALTER TRIGGER "ORION"."TRG_SYNC_CNPJ_ORION_SUP_010" ENABLE;

