CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_DEMANDA" ("ID", "NIVEL", "GRUPO", "SUB", "ITEM", "DEPOSITO", "QUANTIDADE", "PERIODO", "COLECAO", "CONTA_ESTOQUE", "LINHA_PRODUTO", "ARTIGO", "ARTIGO_COTAS", "ORIGEM", "NATUREZA", "NUMERO_CONTROLE", "PEDIDO", "PERMANENTE", "EMBARQUE", "SITUACAO_VENDA") AS 
  select rownum id, live_view_demanda."NIVEL",live_view_demanda."GRUPO",live_view_demanda."SUB",live_view_demanda."ITEM",
                  live_view_demanda."DEPOSITO",live_view_demanda."QUANTIDADE",live_view_demanda."PERIODO",
                  live_view_demanda."COLECAO",live_view_demanda."CONTA_ESTOQUE",live_view_demanda."LINHA_PRODUTO",
                  live_view_demanda."ARTIGO",live_view_demanda."ARTIGO_COTAS",  live_view_demanda."ORIGEM", live_view_demanda."NATUREZA",
                  nvl(live_view_demanda."NUMERO_CONTROLE",0) numero_controle, live_view_demanda."PEDIDO",
                  o.permanente, live_view_demanda."EMBARQUE", live_view_demanda."SITUACAO_VENDA"
from (select a.cd_it_pe_nivel99 nivel, a.cd_it_pe_grupo grupo, a.cd_it_pe_subgrupo sub, a.cd_it_pe_item item,
       a.codigo_deposito deposito, nvl(a.qtde_pedida,0) - nvl(a.qtde_faturada,0) quantidade, p.num_periodo_prod periodo,
       b.colecao, b.conta_estoque, b.linha_produto, b.artigo, b.artigo_cotas, c.origem_prod origem, a.cod_nat_op natureza, p.numero_controle,
       p.pedido_venda pedido, nvl(w.grupo_embarque,0) embarque, p.situacao_venda
from pedi_100 p, pedi_110 a, basi_030 b, basi_010 c, (select min(t.grupo_embarque) grupo_embarque, t.nivel, t.grupo, t.subgrupo, t.item from basi_590 t group by t.nivel, t.grupo, t.subgrupo, t.item) w
where p.situacao_venda  <> 10
  and p.tecido_peca      = '1'
  and a.pedido_venda     = p.pedido_venda
  and a.cod_cancelamento = 0
  and b.nivel_estrutura  = a.cd_it_pe_nivel99
  and b.referencia = a.cd_it_pe_grupo
  and c.nivel_estrutura = a.cd_it_pe_nivel99
  and c.grupo_estrutura = a.cd_it_pe_grupo
  and c.subgru_estrutura = a.cd_it_pe_subgrupo
  and c.item_estrutura = a.cd_it_pe_item
  and w.nivel (+) = a.cd_it_pe_nivel99
  and w.grupo (+) = a.cd_it_pe_grupo
  and w.subgrupo (+) = a.cd_it_pe_subgrupo
  and w.item (+) = a.cd_it_pe_item
  and exists (select 1
                from basi_205
               where basi_205.codigo_deposito = a.codigo_deposito
                 and basi_205.considera_tmrp  = 1)
UNION
select a.item_nivel99 nivel, a.item_grupo grupo, a.item_sub sub, a.item_item item,
       a.codigo_deposito deposito, a.qtde_pedida quantidade, c.periodo_producao periodo,
       b.colecao, b.conta_estoque, b.linha_produto, b.artigo, b.artigo_cotas, d.origem_prod origem, a.cod_nat_op natureza, i.numero_controle,
       i.pedido_venda pedido, nvl(w.grupo_embarque,0) embarque, 0 situacao_venda
from inte_100 i, inte_110 a, basi_030 b, pcpc_010 c, basi_010 d, (select min(t.grupo_embarque) grupo_embarque, t.nivel, t.grupo, t.subgrupo, t.item from basi_590 t group by t.nivel, t.grupo, t.subgrupo, t.item) w
where i.tecido_peca     = '1'
  and i.tipo_registro   = 1
  and a.pedido_venda    = i.pedido_venda
  and b.nivel_estrutura = a.item_grupo
  and b.referencia = a.item_sub
  and c.codigo_empresa = i.codigo_empresa
  and c.area_periodo   = 1
  and i.data_entrega between c.data_ini_fatu and c.data_fim_fatu
  and d.nivel_estrutura = a.item_nivel99
  and d.grupo_estrutura = a.item_grupo
  and d.subgru_estrutura = a.item_sub
  and d.item_estrutura = a.item_item
  and w.nivel (+) = a.item_nivel99
  and w.grupo (+) =  a.item_grupo
  and w.subgrupo (+) = a.item_sub
  and w.item (+) = a.item_item
  and exists (select 1
                from basi_205
               where basi_205.codigo_deposito = a.codigo_deposito
                 and basi_205.considera_tmrp  = 1)) live_view_demanda, orion_vi_produtos o
where o.grupo = live_view_demanda.grupo
order by live_view_demanda."NIVEL",live_view_demanda."GRUPO",live_view_demanda."SUB",live_view_demanda."ITEM",live_view_demanda."DEPOSITO"
;

GRANT SELECT ON "ORION"."ORION_VI_DEMANDA" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_ESTOQUE" ("ID", "NIVEL", "GRUPO", "SUB", "ITEM", "DEPOSITO", "QUANTIDADE", "COLECAO", "CONTA_ESTOQUE", "LINHA_PRODUTO", "ARTIGO", "ARTIGO_COTAS", "ORIGEM", "PERMANENTE", "EMBARQUE") AS 
  select rownum id, a.cditem_nivel99 nivel, a.cditem_grupo grupo, a.cditem_subgrupo sub, a.cditem_item item, a.deposito, a.qtde_estoque_atu quantidade,
       b.colecao, b.conta_estoque, b.linha_produto, b.artigo, b.artigo_cotas, c.origem_prod origem, o.permanente, nvl(w.grupo_embarque,0) embarque
from estq_040 a, basi_030 b, basi_010 c, orion_vi_produtos o, (select min(t.grupo_embarque) grupo_embarque, t.nivel, t.grupo, t.subgrupo, t.item from basi_590 t group by t.nivel, t.grupo, t.subgrupo, t.item) w
where a.cditem_nivel99  = '1'
  and b.nivel_estrutura = a.cditem_nivel99
  and b.referencia = a.cditem_grupo
  and c.nivel_estrutura = a.cditem_nivel99
  and c.grupo_estrutura = a.cditem_grupo
  and c.subgru_estrutura = a.cditem_subgrupo
  and c.item_estrutura = a.cditem_item
  and o.grupo = a.cditem_grupo
  and w.nivel (+) = a.cditem_nivel99
  and w.grupo (+) = a.cditem_grupo
  and w.subgrupo (+) = a.cditem_subgrupo
  and w.item (+) = a.cditem_item
  and exists (select 1
                from basi_205
               where basi_205.codigo_deposito = a.deposito
                 and basi_205.considera_tmrp  = 1)
order by a.cditem_nivel99, a.cditem_grupo, a.cditem_subgrupo, a.cditem_item, a.deposito
;

GRANT SELECT ON "ORION"."ORION_VI_ESTOQUE" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_ITENS" ("ID", "GRUPO", "ITEM", "DESCRICAO", "COLECAO", "EMBARQUE", "ALTERNATIVA_PADRAO", "ROTEIRO_PADRAO", "RISCO_PADRAO", "PERMANENTE") AS 
  select max(rownum) id, b.grupo_estrutura grupo, b.item_estrutura item, max(f.descr_referencia) || ' - ' || max(b.descricao_15) descricao, max(f.colecao) colecao, max(b.codigo_cliente) embarque,
       max(b.numero_alternati) alternativa_padrao, max(b.numero_roteiro) roteiro_padrao, max(f.risco_padrao) risco_padrao,
       nvl((select 1 from basi_140 c
             where c.colecao = f.colecao
               and c.descricao_espanhol like '%COLECAO PERMANENTE%'),0) permanente
 from basi_030 f, basi_010 b
where f.nivel_estrutura = '1'
  and b.nivel_estrutura = f.nivel_estrutura
  and b.grupo_estrutura = f.referencia
group by b.grupo_estrutura, b.item_estrutura, f.colecao
order by b.grupo_estrutura, b.item_estrutura, f.colecao
;

GRANT SELECT ON "ORION"."ORION_VI_ITENS" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_ITENS_PROC_DEM_ABERTO" ("NIVEL", "GRUPO", "SUB", "ITEM", "DESCRICAO", "PERIODO", "QTDE_PEDIDO", "QTDE_PRODUCAO", "DEPOSITO") AS 
  select b.cd_it_pe_nivel99 nivel, b.cd_it_pe_grupo grupo, b.cd_it_pe_subgrupo sub, b.cd_it_pe_item item, c.narrativa descricao,
       a.num_periodo_prod periodo,
       nvl(sum(b.qtde_pedida - b.qtde_faturada),0) qtde_pedido, 0 qtde_producao,
       b.codigo_deposito deposito
from pedi_100 a, pedi_110 b, basi_010 c
where a.tecido_peca = '1'
  and a.situacao_venda <> 10
  and a.cod_cancelamento = 0
  and b.pedido_venda = a.pedido_venda
  and b.cod_cancelamento = 0
  and (b.qtde_pedida - b.qtde_faturada) > 0
  and c.nivel_estrutura = b.cd_it_pe_nivel99
  and c.grupo_estrutura = b.cd_it_pe_grupo
  and c.subgru_estrutura = b.cd_it_pe_subgrupo
  and c.item_estrutura = b.cd_it_pe_item
group by b.cd_it_pe_nivel99, b.cd_it_pe_grupo, b.cd_it_pe_subgrupo, b.cd_it_pe_item, b.codigo_deposito, c.narrativa, a.num_periodo_prod
union
select b.proconf_nivel99 nivel, b.proconf_grupo grupo, b.proconf_subgrupo sub, b.proconf_item item, c.narrativa descricao,
       a.periodo_producao periodo,
       0 qtde_pedido, nvl(sum(b.qtde_a_produzir_pacote),0) qtde_producao,
       a.deposito_entrada deposito
from pcpc_020 a, pcpc_040 b, basi_010 c
where a.cod_cancelamento = 0
  and b.ordem_producao = a.ordem_producao
  and b.codigo_estagio = a.ultimo_estagio
  and b.qtde_a_produzir_pacote > 0
  and c.nivel_estrutura = b.proconf_nivel99
  and c.grupo_estrutura = b.proconf_grupo
  and c.subgru_estrutura = b.proconf_subgrupo
  and c.item_estrutura = b.proconf_item
group by b.proconf_nivel99, b.proconf_grupo, b.proconf_subgrupo, b.proconf_item, a.deposito_entrada, c.narrativa, a.periodo_producao
;

GRANT SELECT ON "ORION"."ORION_VI_ITENS_PROC_DEM_ABERTO" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_ITENS_SUB_COLECOES" ("ID", "COLECAO", "GRUPO", "SUB", "ITEM") AS 
  select rownum id, a.cd_agrupador colecao, a.grupo_ref grupo, b.subgrupo_ref sub, b.item_ref item from basi_631 a, basi_632 b
where b.cd_agrupador (+) = a.cd_agrupador
  and b.grupo_ref (+) = a.grupo_ref
;

GRANT SELECT ON "ORION"."ORION_VI_ITENS_SUB_COLECOES" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_ITENS_X_COLECOES" ("COLECAO", "NIVEL", "REFERENCIA", "TAMANHO", "COR", "DESCRICAO") AS 
  select basi_030.colecao, basi_030.nivel_estrutura nivel, basi_030.referencia, basi_010.subgru_estrutura tamanho, basi_010.item_estrutura cor, basi_010.narrativa descricao
  from SYSTEXTIL.basi_030, SYSTEXTIL.basi_010
 where basi_030.nivel_estrutura = '1'
   and basi_010.nivel_estrutura = basi_030.nivel_estrutura
   and basi_010.grupo_estrutura = basi_030.referencia
   and basi_010.item_ativo = 0
union all
select c.cd_agrupador colecao, a.nivel_estrutura nivel, a.referencia, b.subgru_estrutura tamanho, b.item_estrutura cor, b.narrativa descricao
  from SYSTEXTIL.basi_632 c, SYSTEXTIL.basi_030 a, SYSTEXTIL.basi_010 b
 where a.nivel_estrutura = '1'
   and a.referencia = c.grupo_ref
   and a.colecao in (select basi_140.colecao from SYSTEXTIL.basi_140
                      where basi_140.descricao_espanhol like '%PERMANENTE%')
   and b.nivel_estrutura = '1'
   and b.grupo_estrutura = c.grupo_ref
   and b.subgru_estrutura = c.subgrupo_ref
   and b.item_estrutura = c.item_ref
   and b.item_ativo = 0
;

GRANT SELECT ON "ORION"."ORION_VI_ITENS_X_COLECOES" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_ITENS_X_TEMPO_ESTAGIO" ("ESTAGIO", "NIVEL", "GRUPO", "SUB", "ITEM", "TEMPO") AS 
  select tempo.estagio, tempo.nivel, tempo.grupo, tempo.sub, tempo.item, max(tempo.tempo) tempo
from (select m.codigo_estagio estagio, m.nivel_estrutura nivel, m.grupo_estrutura grupo, m.subgru_estrutura sub, m.item_estrutura item, m.numero_alternati, m.numero_roteiro, sum(m.minutos_homem) tempo
        from mqop_050 m
       where m.nivel_estrutura  = '1'
         and m.minutos_homem > 0
       group by m.nivel_estrutura, m.grupo_estrutura, m.subgru_estrutura, m.item_estrutura, m.numero_alternati, m.numero_roteiro, m.codigo_estagio
       order by m.nivel_estrutura, m.grupo_estrutura, m.subgru_estrutura, m.item_estrutura, m.numero_alternati, m.numero_roteiro, m.codigo_estagio
) tempo
group by tempo.estagio, tempo.nivel, tempo.grupo, tempo.sub, tempo.item
;

GRANT SELECT ON "ORION"."ORION_VI_ITENS_X_TEMPO_ESTAGIO" TO "ABSTRATO";
;

CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_PROCESSO" ("ID", "NIVEL", "GRUPO", "SUB", "ITEM", "PERIODO", "QUANTIDADE", "COLECAO", "CONTA_ESTOQUE", "LINHA_PRODUTO", "ARTIGO", "ARTIGO_COTAS", "ORIGEM", "PERMANENTE", "EMBARQUE") AS 
  select rownum id, a.proconf_nivel99 nivel, a.proconf_grupo grupo, a.proconf_subgrupo sub, a.proconf_item item,
       b.periodo_producao periodo,
       nvl(sum(a.qtde_a_produzir_pacote),0) quantidade,
       --nvl(sum(a.qtde_pecas_prog),0) - nvl(sum(a.qtde_pecas_prod),0) - nvl(sum(a.qtde_pecas_2a),0) - nvl(sum(a.qtde_perdas),0) quantidade,
       --nvl(sum(a.qtde_conserto),0),
       c.colecao, c.conta_estoque, c.linha_produto, c.artigo, c.artigo_cotas, d.origem_prod origem, o.permanente, nvl(w.grupo_embarque,0) embarque
from pcpc_040 a, pcpc_020 b, basi_030 c, basi_010 d, orion_vi_produtos o, (select min(t.grupo_embarque) grupo_embarque, t.nivel, t.grupo, t.subgrupo, t.item from basi_590 t group by t.nivel, t.grupo, t.subgrupo, t.item) w
where b.ordem_producao = a.ordem_producao
  and b.ultimo_estagio = a.codigo_estagio
  and b.cod_cancelamento = 0
  and a.proconf_nivel99  = '1'
  and c.nivel_estrutura  = a.proconf_nivel99
  and c.referencia       = a.proconf_grupo
  and d.nivel_estrutura = a.proconf_nivel99
  and d.grupo_estrutura = a.proconf_grupo
  and d.subgru_estrutura = a.proconf_subgrupo
  and d.item_estrutura = a.proconf_item
  and o.grupo = a.proconf_grupo
  and w.nivel (+) = a.proconf_nivel99
  and w.grupo (+) = a.proconf_grupo
  and w.subgrupo (+) = a.proconf_subgrupo
  and w.item (+) = a.proconf_item
group by rownum, a.proconf_nivel99, a.proconf_grupo, a.proconf_subgrupo, a.proconf_item, b.periodo_producao,
         c.colecao, c.conta_estoque, c.linha_produto, c.artigo, c.artigo_cotas, d.origem_prod, o.permanente, w.grupo_embarque
order by a.proconf_nivel99, a.proconf_grupo, a.proconf_subgrupo, a.proconf_item, b.periodo_producao
;

GRANT SELECT ON "ORION"."ORION_VI_PROCESSO" TO "ABSTRATO";
;

