CREATE OR REPLACE FORCE EDITIONABLE VIEW "ORION"."ORION_VI_VOLUMES_ITENS" ("NUMERO_VOLUME", "NIVEL", "GRUPO", "SUB", "ITEM", "PERIODO_ORDEM", "ORDEM_CONFECCAO", "QTDE_PECAS_REAL", "QTDE_PECAS_SUG", "NUMERO_KIT", "NIVEL_ESTOQUE", "GRUPO_ESTOQUE", "SUB_ESTOQUE", "ITEM_ESTOQUE", "QTDE_QUILOS_ESTOQUE", "ARTIGO_PRODUTO", "SEQ_ITEM_PEDIDO", "QTDE_QUILOS_REAL", "EXECUTA_TRIGGER", "DEPOSITO_ENTRADA_ITEM", "QTDE_PECAS_ATEND", "DEPOSITO_SAIDA_ITEM", "ORDEM_PRODUCAO", "SEQUENCIA_PACK", "NOME_PROGRAMA", "USUARIO_SISTEMA", "PEDIDO_VENDA") AS 
  SELECT A.NUMERO_VOLUME,
       A.NIVEL,
       A.GRUPO,
       A.SUB,
       A.ITEM,
       A.PERIODO_ORDEM,
       A.ORDEM_CONFECCAO,
       A.QTDE_PECAS_REAL,
       A.QTDE_PECAS_SUG ,
       A.NUMERO_KIT     ,
       A.NIVEL_ESTOQUE  ,
       A.GRUPO_ESTOQUE  ,
       A.SUB_ESTOQUE    ,
       A.ITEM_ESTOQUE   ,
       A.QTDE_QUILOS_ESTOQUE,
       A.ARTIGO_PRODUTO     ,
       A.SEQ_ITEM_PEDIDO    ,
       A.QTDE_QUILOS_REAL   ,
       A.EXECUTA_TRIGGER    ,
       A.DEPOSITO_ENTRADA_ITEM,
       A.QTDE_PECAS_ATEND     ,
       A.DEPOSITO_SAIDA_ITEM  ,
       A.ORDEM_PRODUCAO,
       A.SEQUENCIA_PACK,
       A.NOME_PROGRAMA ,
       A.USUARIO_SISTEMA,
       A.PEDIDO_VENDA
FROM PCPC_325 A
WHERE A.PEDIDO_VENDA > 0
UNION
SELECT A.NUMERO_VOLUME,
       A.NIVEL,
       A.GRUPO,
       A.SUB,
       A.ITEM,
       A.PERIODO_ORDEM,
       A.ORDEM_CONFECCAO,
       A.QTDE_PECAS_REAL,
       A.QTDE_PECAS_SUG ,
       A.NUMERO_KIT     ,
       A.NIVEL_ESTOQUE  ,
       A.GRUPO_ESTOQUE  ,
       A.SUB_ESTOQUE    ,
       A.ITEM_ESTOQUE   ,
       A.QTDE_QUILOS_ESTOQUE,
       A.ARTIGO_PRODUTO     ,
       A.SEQ_ITEM_PEDIDO    ,
       A.QTDE_QUILOS_REAL   ,
       A.EXECUTA_TRIGGER    ,
       A.DEPOSITO_ENTRADA_ITEM,
       A.QTDE_PECAS_ATEND     ,
       A.DEPOSITO_SAIDA_ITEM  ,
       A.ORDEM_PRODUCAO,
       A.SEQUENCIA_PACK,
       A.NOME_PROGRAMA ,
       A.USUARIO_SISTEMA,
       B.PEDIDO_VENDA
FROM PCPC_325 A
INNER JOIN PCPC_320 B ON (B.NUMERO_VOLUME = A.NUMERO_VOLUME)
WHERE A.PEDIDO_VENDA = 0
  AND B.PEDIDO_VENDA > 0
;

