CREATE OR REPLACE FUNCTION ORION.LIVE_FN_FORMAT_CPF_CNPJ (
	p_cpf_cnpj9 VARCHAR2,
	p_cpf_cnpj4 VARCHAR2,
	p_cpf_cnpj2 VARCHAR2,
    p_tipo   	NUMBER      -- 1 para CPF, 2 para CNPJ
) 
RETURN VARCHAR2 IS
    v_tamanho NUMBER;
	v_resultado VARCHAR2(40);
	v_cpf_cnpj VARCHAR(40);
BEGIN

    -- Verificar o tipo: 1 para CPF, 2 para CNPJ
    IF p_tipo = 1 THEN
		v_cpf_cnpj :=  LPAD(p_cpf_cnpj9,9,'0')||p_cpf_cnpj4||p_cpf_cnpj2;
		v_cpf_cnpj := REGEXP_REPLACE(v_cpf_cnpj, '[^0-9]', '');
		v_resultado := SUBSTR(v_cpf_cnpj, 1, 3) || '.' ||
			           SUBSTR(v_cpf_cnpj, 4, 3) || '.' ||
                       SUBSTR(v_cpf_cnpj, 7, 3) || '-' ||
                       SUBSTR(v_cpf_cnpj, 10, 2);
	
		RETURN v_resultado;
    ELSIF p_tipo = 2 THEN
    	v_cpf_cnpj :=  LPAD(p_cpf_cnpj9,8,'0')||LPAD(p_cpf_cnpj4,4,'0')||LPAD(p_cpf_cnpj2,2,'0');
	    v_cpf_cnpj := REGEXP_REPLACE(v_cpf_cnpj, '[^0-9]', '');
    	v_resultado := SUBSTR(v_cpf_cnpj, 1, 2) || '.' ||
                       SUBSTR(v_cpf_cnpj, 3, 3) || '.' ||
                       SUBSTR(v_cpf_cnpj, 6, 3) || '/' ||
                       SUBSTR(v_cpf_cnpj, 9, 4) || '-' ||
                       SUBSTR(v_cpf_cnpj, 13, 2);
	ELSE
       v_resultado := 'Tipo inválido. Use 1 para CPF e 2 para CNPJ'; 
       RETURN v_resultado;
    END IF;
    
    RETURN v_resultado;
END;

CREATE OR REPLACE FUNCTION ORION.LIVE_FN_OBTER_DATA_BAIXA(
    p_ORDEM_PRODUCAO IN VARCHAR2,
    p_PERIODO_PRODUCAO IN VARCHAR2,
    p_ORDEM_CONFECCAO IN VARCHAR2
) RETURN DATE IS
    v_data_baixa DATE := NULL;
BEGIN
    -- RETORNA A DATA DA BAIXA
    BEGIN
	
		SELECT MAX(BX_OP.data_producao) INTO v_data_baixa
		FROM pcpc_045 BX_OP
		WHERE BX_OP.PCPC040_ESTCONF = 4
		AND BX_OP.pcpc040_perconf = p_PERIODO_PRODUCAO
		AND BX_OP.pcpc040_ordconf = p_ORDEM_CONFECCAO
		AND BX_OP.ORDEM_PRODUCAO = p_ORDEM_PRODUCAO;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            v_data_baixa := NULL;
    END;
   
    IF v_data_baixa IS NOT NULL THEN
        RETURN v_data_baixa;
    END IF;

    -- VERIFICAR SE A ORDEM POSSUI ESTÁGIO 90 E SE O ESTÁGIO ANTERIOR DO 16 POSSUI BAIXA 
	-- OBS: VERIFICAR O ROTEIRO DA REF. PARA OBTER O ESTÁGIO ANTERIOR

    BEGIN
     
		SELECT (SELECT MAX(BX_OP.data_producao)
				FROM pcpc_045 BX_OP
				WHERE BX_OP.PCPC040_ESTCONF = (SELECT OP1.ESTAGIO_ANTERIOR 
												FROM pcpc_040 OP1
												WHERE OP1.CODIGO_ESTAGIO = 26
												AND OP1.ORDEM_PRODUCAO = OP.ORDEM_PRODUCAO
												AND OP1.ordem_confeccao = OP.ordem_confeccao)
				AND BX_OP.ORDEM_PRODUCAO = OP.ORDEM_PRODUCAO
				AND BX_OP.pcpc040_perconf = OP.periodo_producao
				AND BX_OP.pcpc040_ordconf = OP.ordem_confeccao
				) INTO v_data_baixa
			FROM pcpc_040 OP
			INNER JOIN PCPC_020 PER
				ON PER.ORDEM_PRODUCAO = OP.ORDEM_PRODUCAO 
			INNER JOIN MQOP_050 ROT
				ON ROT.NIVEL_ESTRUTURA = OP.PROCONF_NIVEL99 
				AND ROT.GRUPO_ESTRUTURA = OP.PROCONF_GRUPO 
				AND ROT.NUMERO_ALTERNATI = PER.ALTERNATIVA_PECA 
				AND ROT.NUMERO_ROTEIRO = PER.ROTEIRO_PECA 
				AND ROT.CODIGO_ESTAGIO = OP.CODIGO_ESTAGIO
		WHERE OP.ORDEM_PRODUCAO = p_ORDEM_PRODUCAO
		AND OP.ORDEM_CONFECCAO = p_ORDEM_CONFECCAO								
		AND OP.PERIODO_PRODUCAO = p_PERIODO_PRODUCAO
		AND OP.CODIGO_ESTAGIO = 22;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            v_data_baixa := NULL;
    END;

    IF v_data_baixa IS NOT NULL THEN
        RETURN v_data_baixa;
    END IF;

    -- VERIFICAR SE A ORDEM POSSUI ESTÁGIO 22 E SE O ESTÁGIO ANTERIOR DO 26 POSSUI BAIXA 
	-- OBS: VERIFICAR O ROTEIRO DA REF. PARA OBTER O ESTÁGIO ANTERIOR

    BEGIN
		SELECT (SELECT MAX(BX_OP.data_producao)
				FROM pcpc_045 BX_OP
				WHERE BX_OP.PCPC040_ESTCONF = (SELECT OP1.ESTAGIO_ANTERIOR 
												FROM pcpc_040 OP1
												WHERE OP1.CODIGO_ESTAGIO = 16
												AND OP1.ORDEM_PRODUCAO = OP.ORDEM_PRODUCAO
												AND OP1.ordem_confeccao = OP.ordem_confeccao)
				AND BX_OP.ORDEM_PRODUCAO = OP.ORDEM_PRODUCAO
				AND BX_OP.pcpc040_perconf = OP.periodo_producao
				AND BX_OP.pcpc040_ordconf = OP.ordem_confeccao
				) INTO v_data_baixa
			FROM pcpc_040 OP
			INNER JOIN PCPC_020 PER
				ON PER.ORDEM_PRODUCAO = OP.ORDEM_PRODUCAO 
			INNER JOIN MQOP_050 ROT
				ON ROT.NIVEL_ESTRUTURA = OP.PROCONF_NIVEL99 
				AND ROT.GRUPO_ESTRUTURA = OP.PROCONF_GRUPO 
				AND ROT.NUMERO_ALTERNATI = PER.ALTERNATIVA_PECA 
				AND ROT.NUMERO_ROTEIRO = PER.ROTEIRO_PECA 
				AND ROT.CODIGO_ESTAGIO = OP.CODIGO_ESTAGIO
		WHERE OP.ORDEM_PRODUCAO = p_ORDEM_PRODUCAO
		AND OP.ORDEM_CONFECCAO = p_ORDEM_CONFECCAO								
		AND OP.PERIODO_PRODUCAO = p_PERIODO_PRODUCAO
		AND OP.CODIGO_ESTAGIO = 90;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            v_data_baixa := NULL;
    END;

    RETURN v_data_baixa;

END LIVE_FN_OBTER_DATA_BAIXA;

CREATE OR REPLACE FUNCTION ORION.LIVE_FN_VALOR_TOTAL_NOTA (
    p_codigo_empresa  IN fatu_060.ch_it_nf_cd_empr%TYPE,
    p_num_nota_fiscal IN fatu_060.ch_it_nf_num_nfis%TYPE,
    p_serie_nota_fisc IN fatu_060.ch_it_nf_ser_nfis%TYPE
) RETURN NUMBER IS
    v_valor_total NUMBER := 0;
BEGIN
    SELECT
        (f050.valor_itens_nfis + f050.valor_ipi + f050.valor_encar_nota  + f050.valor_frete_nfis +
         f050.valor_seguro - f050.valor_desc_nota - f050.valor_suframa + f050.valor_despesas - f050.vlr_desc_especial + f050.valor_icms_sub)
    INTO v_valor_total
    FROM fatu_050 f050
    WHERE f050.codigo_empresa = p_codigo_empresa
      AND f050.num_nota_fiscal = p_num_nota_fiscal
      AND f050.serie_nota_fisc = p_serie_nota_fisc
      AND f050.pedido_venda <> 0
      AND f050.situacao_nfisc <> 2;

    RETURN v_valor_total;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN 0; -- Retorna 0 se nenhuma nota fiscal for encontrada
    WHEN OTHERS THEN
        RAISE; -- Relança outros erros
END;
;

CREATE OR REPLACE PROCEDURE ORION.LIVE_PR_INSERIR_RELACIONAMENTO_GERFAC
IS
    CURSOR C_CNPJS IS
        SELECT CNPJ
        FROM ORION_INTEG_GERFAC_FACCAO
        WHERE STATUS = 1;

    TYPE T_CONFIG IS RECORD (
        COD_SERVICO NUMBER,
        CONSERTO    NUMBER
    );

    TYPE T_CONFIG_LIST IS TABLE OF T_CONFIG;

    V_CONFIGS T_CONFIG_LIST := T_CONFIG_LIST(
        T_CONFIG(21, 0),
        T_CONFIG(50, 1),
        T_CONFIG(55, 1)
    );

    V_ID_REL_FAC   NUMBER;
    V_SEQ_ID       NUMBER := 1; -- contador de ID (ajuste se tiver sequence)
    V_FASE         VARCHAR2(4) := 'COST';
    V_ESTAGIO      NUMBER := 20;
BEGIN
    FOR CNPJ_REC IN C_CNPJS LOOP
        FOR I IN 1 .. V_CONFIGS.COUNT LOOP
            -- Gerar novo ID para relacionamento
            V_ID_REL_FAC := V_SEQ_ID;

            -- Inserir na tabela principal
            INSERT INTO ORION_INTEG_GERFAC_FACCAO_RELACIONAMENTO (
                ID, CNPJ, FASE, COD_SERVICO, CONSERTO
            ) VALUES (
                V_ID_REL_FAC,
                CNPJ_REC.CNPJ,
                V_FASE,
                V_CONFIGS(I).COD_SERVICO,
                V_CONFIGS(I).CONSERTO
            );

            -- Inserir na tabela de estágios
            INSERT INTO ORION_INTEG_GERFAC_FACCAO_RELACIONAMENTO_ESTAGIO (
                ID, ID_REL_FAC, ESTAGIO
            ) VALUES (
                V_SEQ_ID * 10,  -- ID fictício
                V_ID_REL_FAC,
                V_ESTAGIO
            );

            V_SEQ_ID := V_SEQ_ID + 1;
        END LOOP;
    END LOOP;

    COMMIT;
EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RAISE;
END;
;

CREATE OR REPLACE FUNCTION ORION."ORION_FN_CALCULA_VALOR_LIQ_PED" (p_pedido in number) return number
is
    v_valor_liq_unit      number;
    v_valor_liq_itens     number;
    v_col_tab_preco       number;
    v_mes_tab_preco       number;
    v_seq_tab_preco       number;
    v_casas_decimais      number;
    v_valor_final         number;
    v_desconto1           number;
    v_desconto2           number;
    v_desconto3           number;
begin
   v_valor_liq_unit := 0;
   v_valor_liq_itens := 0;
   v_valor_final := 0;
   v_desconto1 := 0;
   v_desconto2 := 0;
   v_desconto3 := 0;
   v_casas_decimais := 0;

   begin
     select pedi_100.valor_liq_itens, pedi_100.colecao_tabela, pedi_100.mes_tabela, pedi_100.sequencia_tabela,
     pedi_100.desconto1, pedi_100.desconto2, pedi_100.desconto3
            into v_valor_liq_itens, v_col_tab_preco, v_mes_tab_preco, v_seq_tab_preco, v_desconto1, v_desconto2, v_desconto3
     from pedi_100
     where pedi_100.pedido_venda = p_pedido;
   end;

   begin
     select pedi_090.casas_decimais
                INTO v_casas_decimais
     from pedi_090
          where pedi_090.col_tabela_preco = v_col_tab_preco
             and pedi_090.mes_tabela_preco = v_mes_tab_preco
             and pedi_090.seq_tabela_preco = v_seq_tab_preco;
       exception when others then
         v_casas_decimais := 5;
   end;

   for dadosItem in (select pedi_110.qtde_pedida - pedi_110.qtde_faturada qtdePedida, pedi_110.valor_unitario valorUnitario, pedi_110.percentual_desc percDesc
                     from pedi_110
                     where pedi_110.pedido_venda = p_pedido
                     and pedi_110.cod_cancelamento = 0
                     )
   loop
       v_valor_liq_unit := dadosItem.Valorunitario - dadosItem.Valorunitario *(dadosItem.Percdesc) / 100.00;

       begin
         select round( v_valor_liq_unit, v_casas_decimais)
            INTO v_valor_liq_unit
         from dual;
         exception when others then
            v_valor_liq_unit := dadosItem.Valorunitario - dadosItem.Valorunitario * ((dadosItem.Percdesc) /100.00 );
       end;

       v_valor_final := v_valor_final + dadosItem.Qtdepedida * v_valor_liq_unit;
    end loop;

      v_valor_final := v_valor_final - (v_valor_final * v_desconto1 / 100);
      v_valor_final := v_valor_final - (v_valor_final * v_desconto2 / 100);
      v_valor_final := v_valor_final - (v_valor_final * v_desconto3 / 100);

   return v_valor_final;
end;
;

CREATE OR REPLACE FUNCTION ORION.ORION_FN_PORCENTAGEM_FRANCHISING(
    cnpj9_param IN NUMBER,
    cnpj4_param IN NUMBER,
    cnpj2_param IN NUMBER,
    data_str_param IN VARCHAR2
) RETURN NUMBER
IS
    porcentagem NUMBER;
    data_vigencia DATE;
BEGIN
    data_vigencia := TO_DATE(data_str_param, 'DD/MM/YYYY');

    SELECT MAX(porcentagem)
    INTO porcentagem
    FROM orion_com_320
    WHERE cnpj9 = cnpj9_param
    AND cnpj4 = cnpj4_param
    AND cnpj2 = cnpj2_param
    AND data_inicio = (
        SELECT MAX(data_inicio)
        FROM orion_com_320
        WHERE cnpj9 = cnpj9_param
        AND cnpj4 = cnpj4_param
        AND cnpj2 = cnpj2_param
        AND data_inicio <= data_vigencia
    );

    RETURN porcentagem;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN NULL;
END;

CREATE OR REPLACE PROCEDURE ORION.ORION_PR_ACERTA_QTD_REAL_PEDIDO(p_pedido IN NUMBER) AS

  CURSOR c_volume_tag IS
    SELECT
      v.pedido_venda,
      v.numero_volume,
      v.seq_item_pedido,
      SUM(v.qtdPecasTag)    AS qtdPecasTag,
      SUM(v.qtde_pecas_real) AS qtdPecasReal
    FROM (
      SELECT
        a.PEDIDO_VENDA,
        a.NUMERO_VOLUME,
        b.SEQ_ITEM_PEDIDO,
        b.QTDE_PECAS_REAL,
        (
          SELECT COUNT(*)
          FROM pcpc_330 c
          WHERE c.PEDIDO_VENDA      = a.PEDIDO_VENDA
            AND c.SEQ_ITEM_PEDIDO   = b.SEQ_ITEM_PEDIDO
            AND c.NR_VOLUME         = a.NUMERO_VOLUME
        ) AS qtdPecasTag
      FROM pcpc_320 a
      JOIN pcpc_325 b
        ON a.NUMERO_VOLUME = b.NUMERO_VOLUME
      WHERE a.SITUACAO_VOLUME = 1
        AND (a.PEDIDO_VENDA = p_pedido OR p_pedido IS NULL)
    ) v
    JOIN pedi_110 p
      ON p.PEDIDO_VENDA     = v.PEDIDO_VENDA
     AND p.SEQ_ITEM_PEDIDO  = v.SEQ_ITEM_PEDIDO
    WHERE NOT EXISTS (
      SELECT 1
      FROM orion_exp_470 y
      WHERE y.pedido_onda = v.pedido_venda
        AND y.situacao_pedido <> 5
    )
      AND NOT EXISTS (
      SELECT 1
      FROM orion_exp_480 t
      WHERE t.numero_pedido = v.pedido_venda
        AND t.situacao      = 'PENDENTE'
    )
    GROUP BY
      v.pedido_venda,
      v.numero_volume,
      v.seq_item_pedido
    HAVING
          SUM(v.qtdPecasTag)    > 0 
      AND SUM(v.qtdPecasTag)    <> SUM(v.qtde_pecas_real);

BEGIN
  FOR rec IN c_volume_tag LOOP

    -- 1) Ajusta qtde_pecas_real em pcpc_325

    BEGIN
      IF rec.qtdPecasReal <> rec.qtdPecasTag THEN
        UPDATE pcpc_325 b
        SET b.qtde_pecas_real = rec.qtdPecasTag
        WHERE b.numero_volume     = rec.numero_volume
          AND b.seq_item_pedido    = rec.seq_item_pedido
          AND b.qtde_pecas_real   <> rec.qtdPecasTag;
      END IF;
    EXCEPTION
      WHEN OTHERS THEN
        NULL;
    END;

  END LOOP;
END ORION_PR_ACERTA_QTD_REAL_PEDIDO;
;

CREATE OR REPLACE PROCEDURE ORION.ORION_PR_ACERTO_PEDIDO_SUGESTAO(p_pedido IN NUMBER) AS

  CURSOR c_volume_tag IS
    SELECT
      v.pedido_venda,
      v.seq_item_pedido,
      SUM(v.qtdPecasTag) AS qtdPecasTag,
      SUM(v.QTDE_PECAS_REAL) AS qtdPecasReal,
      p.QTDE_AFATURAR,
      f.QTDE_DISPONIVEL,
      p.QTDE_PEDIDA - p.QTDE_FATURADA AS saldoPedido
    FROM (
      SELECT
        a.PEDIDO_VENDA,
        b.SEQ_ITEM_PEDIDO,
        b.QTDE_PECAS_REAL,
        (
          SELECT COUNT(*)
          FROM pcpc_330 c
          WHERE c.PEDIDO_VENDA = a.PEDIDO_VENDA
            AND c.SEQ_ITEM_PEDIDO = b.SEQ_ITEM_PEDIDO
            AND c.NR_VOLUME = a.NUMERO_VOLUME
        ) AS qtdPecasTag
      FROM pcpc_320 a
      JOIN pcpc_325 b ON a.NUMERO_VOLUME = b.NUMERO_VOLUME
      WHERE a.SITUACAO_VOLUME = 1
        AND (a.PEDIDO_VENDA = p_pedido OR p_pedido IS NULL)
    ) v
    INNER JOIN pedi_110 p
      ON p.PEDIDO_VENDA = v.PEDIDO_VENDA
     AND p.SEQ_ITEM_PEDIDO = v.SEQ_ITEM_PEDIDO
    INNER JOIN pedi_100 r
      ON r.PEDIDO_VENDA = v.PEDIDO_VENDA
    INNER JOIN fatu_780 f
      ON f.PEDIDO = v.PEDIDO_VENDA
     AND f.SEQUENCIA = v.SEQ_ITEM_PEDIDO
    WHERE NOT EXISTS (SELECT 1 FROM orion_exp_470 y WHERE y.pedido_onda = r.pedido_venda AND y.situacao_pedido <> 5)
    AND NOT EXISTS (SELECT 1 FROM orion_exp_480 t WHERE t.numero_pedido = r.pedido_venda AND t.situacao = 'PENDENTE')
    GROUP BY
      v.pedido_venda,
      v.seq_item_pedido,
      p.QTDE_AFATURAR,
      f.QTDE_DISPONIVEL,
      p.QTDE_PEDIDA,
      p.QTDE_FATURADA
    HAVING
      SUM(v.qtdPecasTag) <> SUM(v.QTDE_PECAS_REAL)
      OR SUM(v.qtdPecasTag) <> p.QTDE_AFATURAR
      OR SUM(v.qtdPecasTag) <> f.QTDE_DISPONIVEL;

BEGIN
  FOR rec IN c_volume_tag LOOP

  BEGIN
    IF (rec.qtdPecasReal = rec.qtdPecasTag) and (rec.saldoPedido >= rec.qtdPecasTag) THEN

      BEGIN
        IF rec.qtdPecasTag <> rec.QTDE_AFATURAR THEN
          UPDATE pedi_110 a
          SET a.QTDE_AFATURAR = rec.qtdPecasTag
          WHERE a.PEDIDO_VENDA = rec.pedido_venda
            AND a.SEQ_ITEM_PEDIDO = rec.seq_item_pedido;
        END IF;
      EXCEPTION
        WHEN OTHERS THEN
          -- log erro ou trace opcional aqui
          NULL;
      END;

      BEGIN
        IF rec.QTDE_DISPONIVEL <> rec.qtdPecasTag THEN
          UPDATE fatu_780 a
          SET a.QTDE_DISPONIVEL = rec.qtdPecasTag
          WHERE a.PEDIDO = rec.pedido_venda
            AND a.SEQUENCIA = rec.seq_item_pedido;
        END IF;
      EXCEPTION
        WHEN OTHERS THEN
          -- log erro ou trace opcional aqui
          NULL;
      END;

    END IF;
  END;
  
  END LOOP;
END;
;

CREATE OR REPLACE PROCEDURE ORION.ORION_PR_ATUALIZA_CAPA_PEDIDO(p_pedido IN NUMBER) AS

   v_qtde_total_saldo       NUMBER := 0;
   v_valor_total_saldo      NUMBER := 0;
   v_valor_liq_itens        NUMBER := 0;
   v_valor_total_pedi       NUMBER := 0;
   v_qtde_total_pedi        NUMBER := 0;
   v_qtde_itens_cancelados  NUMBER := 0;
   v_valor_itens_cancelados NUMBER := 0;
   v_saldo_qtde             NUMBER := 0;
   v_saldo_valor            NUMBER := 0;

BEGIN

   FOR r_pedido IN (
      SELECT a.pedido_venda
        FROM pedi_100 a
       WHERE (a.pedido_venda = p_pedido OR p_pedido IS NULL)
         AND a.cod_cancelamento = 0
         AND a.situacao_venda <> 10
         AND a.data_emis_venda > to_date('01-01-2025', 'DD-MM-YYYY')
   ) LOOP

      -- Zera variáveis
      v_qtde_total_saldo       := 0;
      v_valor_total_saldo      := 0;
      v_valor_liq_itens        := 0;
      v_valor_total_pedi       := 0;
      v_qtde_total_pedi        := 0;
      v_qtde_itens_cancelados  := 0;
      v_valor_itens_cancelados := 0;
      v_saldo_qtde             := 0;
      v_saldo_valor            := 0;

      -- Soma itens cancelados - quantidade
      SELECT NVL(SUM(a.qtde_pedida - a.qtde_faturada), 0)
        INTO v_qtde_itens_cancelados
        FROM pedi_110 a
       WHERE a.pedido_venda = r_pedido.pedido_venda
         AND a.cod_cancelamento <> 0;

      -- Soma itens cancelados - valor
      SELECT NVL(SUM((a.qtde_pedida - a.qtde_faturada) *
                    (a.valor_unitario - (a.valor_unitario * (a.percentual_desc / 100)))), 0)
        INTO v_valor_itens_cancelados
        FROM pedi_110 a
       WHERE a.pedido_venda = r_pedido.pedido_venda
         AND a.cod_cancelamento <> 0;

      -- Loop nos itens do pedido
      FOR r IN (
         SELECT a.valor_unitario AS valorUnit,
                a.qtde_pedida    AS qtdePedida,
                a.qtde_faturada  AS qtdeFaturada,
                a.percentual_desc AS percDesc
           FROM pedi_110 a
          WHERE a.pedido_venda = r_pedido.pedido_venda
      ) LOOP
         v_qtde_total_saldo := v_qtde_total_saldo + (r.qtdePedida - r.qtdeFaturada);
         v_valor_total_saldo := v_valor_total_saldo + (r.qtdePedida - r.qtdeFaturada) * (r.valorUnit - (r.valorUnit * (r.percDesc / 100)));
         v_valor_liq_itens := v_valor_liq_itens + r.qtdePedida * (r.valorUnit - (r.valorUnit * (r.percDesc / 100)));
         v_valor_total_pedi := v_valor_total_pedi + (r.valorUnit * r.qtdePedida);
         v_qtde_total_pedi := v_qtde_total_pedi + r.qtdePedida;
      END LOOP;

      -- Cálculo dos saldos finais
      v_saldo_qtde := v_qtde_total_saldo - v_qtde_itens_cancelados;
      v_saldo_valor := v_valor_total_saldo - v_valor_itens_cancelados;

      -- Verifica se há divergência antes de atualizar
      DECLARE
         v_qtde_saldo_pedi    NUMBER := 0;
         v_valor_saldo_pedi   NUMBER := 0;
         v_valor_liq_itens_bd NUMBER := 0;
         v_valor_total_pedi_bd NUMBER := 0;
         v_qtde_total_pedi_bd NUMBER := 0;
      BEGIN
         SELECT qtde_saldo_pedi,
                valor_saldo_pedi,
                valor_liq_itens,
                valor_total_pedi,
                qtde_total_pedi
           INTO v_qtde_saldo_pedi,
                v_valor_saldo_pedi,
                v_valor_liq_itens_bd,
                v_valor_total_pedi_bd,
                v_qtde_total_pedi_bd
           FROM pedi_100
          WHERE pedido_venda = r_pedido.pedido_venda;

          v_saldo_qtde := ROUND(v_saldo_qtde, 2);
          v_saldo_valor := ROUND(v_saldo_valor, 2);
          v_valor_liq_itens := ROUND(v_valor_liq_itens, 2);
          v_valor_total_pedi := ROUND(v_valor_total_pedi, 2);
          v_qtde_total_pedi := ROUND(v_qtde_total_pedi, 2);

         IF v_qtde_saldo_pedi   <> v_saldo_qtde OR
            v_valor_saldo_pedi  <> v_saldo_valor OR
            v_valor_liq_itens_bd <> v_valor_liq_itens OR
            v_valor_total_pedi_bd <> v_valor_total_pedi OR
            v_qtde_total_pedi_bd <> v_qtde_total_pedi THEN

            UPDATE pedi_100 a
               SET a.qtde_saldo_pedi   = v_saldo_qtde,
                   a.valor_saldo_pedi  = v_saldo_valor,
                   a.valor_liq_itens   = v_valor_liq_itens,
                  a.valor_total_pedi  = v_valor_total_pedi,
                   a.qtde_total_pedi   = v_qtde_total_pedi
             WHERE a.pedido_venda = r_pedido.pedido_venda;

            --INSERT INTO orion_tmp_pedi_100_atualizacao (
            --   pedido_venda,
            --   old_qtde_saldo_pedi,
            --   new_qtde_saldo_pedi,
            --   old_valor_saldo_pedi,
            --   new_valor_saldo_pedi,
            --   old_valor_liq_itens,
            --   new_valor_liq_itens,
            --   old_valor_total_pedi,
            --   new_valor_total_pedi,
            --   old_qtde_total_pedi,
            --   new_qtde_total_pedi
            --) VALUES (
            --   r_pedido.pedido_venda,
            --   v_qtde_saldo_pedi,
            --   v_saldo_qtde,
            --   v_valor_saldo_pedi,
            --   v_saldo_valor,
            --   v_valor_liq_itens_bd,
            --   v_valor_liq_itens,
            --   v_valor_total_pedi_bd,
            --   v_valor_total_pedi,
            --   v_qtde_total_pedi_bd,
            --   v_qtde_total_pedi
            --);
         END IF;
      END;

   END LOOP;

   COMMIT;

EXCEPTION
   WHEN OTHERS THEN
      ROLLBACK;
      RAISE;

END ORION_PR_ATUALIZA_CAPA_PEDIDO;
;

CREATE OR REPLACE PROCEDURE ORION."ORION_PR_CONGELA_PEDIDOS"
IS
   CURSOR cur_pedidos IS
      SELECT a.pedido_venda,       a.data_entr_venda, a.situacao_venda,   a.cod_cancelamento,
             a.sit_aloc_pedi,      a.sit_coletor,     a.situacao_coleta,  a.status_expedicao,
             a.status_homologacao, a.status_pedido,   a.status_comercial, a.sit_conferencia,
             a.qtde_saldo_pedi,    a.valor_saldo_pedi
        FROM pedi_100 a
       WHERE a.data_entr_venda = TRUNC(SYSDATE-1)
         AND a.qtde_total_pedi > 0;

   CURSOR cur_motiv_bloqueio (p_pedido number) IS
      SELECT a.pedido_venda, a.seq_situacao, a.codigo_situacao, a.flag_liberacao, a.data_situacao, a.data_liberacao
        FROM pedi_135 a
       WHERE a.pedido_venda = p_pedido;

-- Rodrigo F.
-- Congela os pedidos com embarque do dia anterior, para conferência e análise em relatórios e BIŽs.

BEGIN

   FOR reg_pedidos IN cur_pedidos
   LOOP

      BEGIN
         INSERT INTO orion_com_310 (PEDIDO_VENDA,                   DATA_ENTR_VENDA,             SITUACAO_VENDA,              COD_CANCELAMENTO,
                                    SIT_ALOC_PEDI,                  SIT_COLETOR,                 SITUACAO_COLETA,             STATUS_EXPEDICAO,
                                    STATUS_HOMOLOGACAO,             STATUS_PEDIDO,               STATUS_COMERCIAL,            SIT_CONFERENCIA, 
                                    QTDE_SALDO_PEDI,                VALOR_SALDO_PEDI)
                            VALUES (reg_pedidos.pedido_venda,       reg_pedidos.data_entr_venda, reg_pedidos.situacao_venda,  reg_pedidos.cod_cancelamento,
                                    reg_pedidos.sit_aloc_pedi,      reg_pedidos.sit_coletor,     reg_pedidos.situacao_coleta, reg_pedidos.status_expedicao,
                                    reg_pedidos.status_homologacao, reg_pedidos.status_pedido,   reg_pedidos.status_comercial,reg_pedidos.sit_conferencia,
                                    reg_pedidos.qtde_saldo_pedi,    reg_pedidos.valor_saldo_pedi);
         EXCEPTION
            WHEN OTHERS THEN NULL;
      END;

      FOR reg_motiv_bloqueio IN cur_motiv_bloqueio(reg_pedidos.pedido_venda)
      LOOP

         BEGIN
            INSERT INTO orion_com_311 (PEDIDO_VENDA, SEQ_SITUACAO, CODIGO_SITUACAO, FLAG_LIBERACAO, DATA_SITUACAO, DATA_LIBERACAO)
                               VALUES (REG_MOTIV_BLOQUEIO.PEDIDO_VENDA, REG_MOTIV_BLOQUEIO.SEQ_SITUACAO, REG_MOTIV_BLOQUEIO.CODIGO_SITUACAO, REG_MOTIV_BLOQUEIO.FLAG_LIBERACAO, REG_MOTIV_BLOQUEIO.DATA_SITUACAO, REG_MOTIV_BLOQUEIO.DATA_LIBERACAO);
            EXCEPTION
               WHEN OTHERS THEN NULL;
         END;

      END LOOP;

      COMMIT;
   END LOOP;

END ORION_PR_CONGELA_PEDIDOS;
;

CREATE OR REPLACE PROCEDURE ORION.ORION_PR_DELETA_IMG_INSP_QLDADE IS
BEGIN
    DELETE FROM orion_anexos
    WHERE data_registro < SYSDATE - INTERVAL '2' MONTH
    AND programa_gerador = 'Inspeção Qualidade';

    COMMIT;

    DBMS_OUTPUT.PUT_LINE('Registros deletados com sucesso.');
EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Erro ao deletar registros: ' || SQLERRM);
END ORION_PR_DELETA_IMG_INSP_QLDADE;
;

CREATE OR REPLACE PROCEDURE ORION.ORION_PR_DELETE_DEP_200
IS
BEGIN
    DELETE FROM basi_015 a
    WHERE a.ROWID IN (
        SELECT rid
        FROM (
            SELECT a2.ROWID rid
            FROM basi_015 a2
            WHERE a2.codigo_empresa = 1
              AND a2.codigo_deposito = 200
              AND NOT EXISTS (
                    SELECT 1
                    FROM basi_015 b
                    WHERE b.codigo_empresa   = a2.codigo_empresa
                      AND b.nivel_estrutura  = a2.nivel_estrutura
                      AND b.grupo_estrutura  = a2.grupo_estrutura
                      AND b.subgru_estrutura = a2.subgru_estrutura
                      AND b.item_estrutura   = a2.item_estrutura
                      AND b.codigo_deposito IN (902, 991)
              )
              AND ROWNUM <= 500
        )
    );

    COMMIT;
END ORION_PR_DELETE_DEP_200;
;

CREATE OR REPLACE procedure ORION.ORION_PR_INSERT_ORION_002 ( p_descricao in VARCHAR2, p_modulo in VARCHAR2, p_path in VARCHAR2, p_help in VARCHAR2 default null ) as v_id number;
  v_registros number;
begin
   select  COUNT(a.id) into v_registros  from 	orion_002 a
   where a.descricao = p_descricao
 	 and a.modulo = p_modulo
	 and a.path = p_path;

   if (v_registros > 0) then 
     RAISE_APPLICATION_ERROR(-20001,  'Já existe um registro com os mesmos valores de descricao, modulo e path.');
   else
     select nVL(MAX(id), 0) + 1 into v_id from	orion_002;
     insert into orion_002(id,	descricao,	modulo,	path,	help) values (v_id, p_descricao, p_modulo, p_path, p_help);
     commit;
   end if;
end;

;

CREATE OR REPLACE PROCEDURE ORION."ORION_PR_LIMPA_TAGS_CAIXAS"
IS
-- Rodrigo F. - Ch. 73535
-- Exclusão dos tags que estão fora de estoque das caixas que estão no abastecimento da expedição (Somente para o deposito 4)

BEGIN
   BEGIN
      DELETE FROM orion_131 o
      WHERE EXISTS (SELECT 1 FROM pcpc_330 t
                     WHERE t.periodo_producao = o.PERIODO_PRODUCAO
                       AND t.ordem_producao   = o.ORDEM_PRODUCAO
                       AND t.ordem_confeccao  = o.ORDEM_CONFECCAO
                       AND t.sequencia        = o.SEQUENCIA
                       AND t.estoque_tag     <> 1)
             AND EXISTS (select 1 from orion_130 r where r.numero_caixa = o.numero_caixa and r.deposito_destino = 4);
      EXCEPTION
         WHEN OTHERS THEN NULL;
   END;

   COMMIT;

END ORION_PR_LIMPA_TAGS_CAIXAS;
;

CREATE SEQUENCE ORION.CONVERSAO_LOJA_SEQ INCREMENT BY 1 MINVALUE 1 MAXVALUE 9999999999999999999999999999 NOCYCLE CACHE 20 NOORDER ;

CREATE SEQUENCE ORION.ID_ORION_EXP_410 INCREMENT BY 1 MINVALUE 1 MAXVALUE 9999999999999999999999999999 NOCYCLE CACHE 20 NOORDER ;

